/** Define allowed svgs. */
function portfolio_2026_allowed_svg_tags() {
	return array(
		'svg'  => array(
			'xmlns'           => array(),
			'width'           => array(),
			'height'          => array(),
			'viewbox'         => array(),
			'viewBox'         => array(),
			'fill'            => array(),
			'stroke'          => array(),
			'stroke-linecap'  => array(),
			'stroke-linejoin' => array(),
			'class'           => array(),
			'aria-hidden'     => array(),
		),
		'rect' => array(
			'x'         => array(),
			'y'         => array(),
			'width'     => array(),
			'height'    => array(),
			'rx'        => array(),
			'ry'        => array(),
			'fill'      => array(),
			'transform' => array(),
		),
		'path' => array(
			'd'               => array(),
			'fill'            => array(),
			'fill-rule'       => array(),
			'clip-rule'       => array(),
			'stroke'          => array(),
			'stroke-width'    => array(),
			'stroke-linecap'  => array(),
			'stroke-linejoin' => array(),
		),
	);
}
